mapper.select:
SELECT co.id, co.slot_id, co.status, CASE WHEN co.status IN ('CONFIRMED', 'COMPLETED') THEN cs.address ELSE NULL END AS address, co.creator_id, co.message, co.create_time, cs.start_time, cs.end_time, cs.price, su.nickname AS creator_name, su.avatar AS creator_avatar, ra.reject_reason AS reject_reason FROM consult_order co LEFT JOIN consult_slot cs ON co.slot_id = cs.id LEFT JOIN sys_user su ON co.creator_id = su.id LEFT JOIN refund_apply ra ON co.id = ra.order_id AND ra.status = 'PROCESSED' WHERE co.user_id = #{userId}
AND co.status = #{query.status}
AND cs.start_time >= #{query.startTime}
AND cs.start_time <= #{query.endTime}
ORDER BY co.create_time DESC
